print(f"Years found: {sorted(yearly_cpc_counts.keys())}")
print(f"CPC groups found: {len(cpc_full_titles)}")

print('__RESULT__:')
print(json.dumps({
    'status': 'prepared',
    'total_patents': grand_total_patents,
    'years': sorted(list(yearly_cpc_counts.keys())),
    'cpc_groups': len(cpc_full_titles)
}))"}

